    <script>
        const triggerQuickReply = (text) => {
            if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${text}|/trigger`);
            } else {
                console.log('SillyTavern environment not detected. Would send:', text);
            }
        };

        document.addEventListener('DOMContentLoaded', () => {
            initThemeToggle();
            const storyRenderer = new StoryRenderer('yaml-data-source');
            storyRenderer.init();
            document.getElementById('options-container').addEventListener('click', (e) => {
                const optionEl = e.target.closest('li');
                if (optionEl && optionEl.parentElement.id === 'options-list') {
                    const optionText = optionEl.dataset.fulltext;
                    triggerQuickReply(optionText);
                    const originalBg = optionEl.style.backgroundColor;
                    optionEl.style.backgroundColor = 'rgba(157, 124, 245, 0.2)';
                    setTimeout(() => { optionEl.style.backgroundColor = originalBg; }, 300);
                }
            });
        });

        function initThemeToggle() {
            const themeButtons = document.querySelectorAll('.theme-btn');
            const body = document.body;
            const savedTheme = localStorage.getItem('storyTheme') || 'night';

            const activateTheme = (theme) => {
                const themes = ['night-mode', 'day-mode', 'jade-mode', 'classic-mode'];
                // 只在 body 上切换主题模式类，不触碰其他 class
                const currentClasses = Array.from(body.classList);
                themes.forEach(t => {
                    const index = currentClasses.indexOf(t);
                    if (index > -1) {
                        currentClasses.splice(index, 1);
                    }
                });
                currentClasses.push(`${theme}-mode`);
                body.className = currentClasses.join(' ');


                themeButtons.forEach(btn => {
                    btn.classList.toggle('active', btn.dataset.theme === theme);
                });
                localStorage.setItem('storyTheme', theme);
            };

            themeButtons.forEach(button => {
                button.addEventListener('click', () => activateTheme(button.dataset.theme));
            });

            activateTheme(savedTheme);
        }

        class StoryRenderer {
            constructor(dataSourceId) {
                this.dataSourceId = dataSourceId;
                this.initElements();
            }

            initElements() {
                this.elements = {
                    statusBarTitle: document.getElementById('status-bar-title'),
                    timeDisplay: document.getElementById('time-display'),
                    locationDisplay: document.getElementById('location-display'),
                    charactersContainer: document.getElementById('characters-container'),
                    actionOwner: document.getElementById('action-owner'),
                    optionsList: document.getElementById('options-list')
                };
            }

            init() {
                try {
                    const scriptElement = document.getElementById(this.dataSourceId);
                    if (!scriptElement) throw new Error('Không tìm thấy nguồn dữ liệu YAML');
                    this.rawYamlContent = scriptElement.textContent.trim();
                    if (!this.rawYamlContent) { this.renderEmpty(); return; }
                    this.yamlData = jsyaml.load(this.rawYamlContent);
                    const rootNodeName = Object.keys(this.yamlData)[0];
                    if (!rootNodeName) throw new Error('Định dạng dữ liệu YAML không chính xác');
                    this.rootData = this.yamlData[rootNodeName];
                    this.renderAll(rootNodeName);
                } catch (error) { this.handleError(error); }
            }

            getEmoji(text) { return (text.match(/[\p{Emoji_Presentation}\p{Emoji}\uFE0F]/u) || [''])[0]; }
            cleanText(text) { return String(text).replace(/[\p{Emoji_Presentation}\p{Emoji}\uFE0F]/u, '').trim(); }

            findField(data, keywords) {
                const dataKeys = Object.keys(data || {});
                return dataKeys.find(key => keywords.some(kw => key.toLowerCase().includes(kw))) || null;
            }

            renderAll(rootNodeName) {
                document.body.classList.add('theme-transition'); // Add transition class to body
                this.elements.statusBarTitle.textContent = rootNodeName;
                this.renderHeader();
                this.renderCharacters();
                this.renderActionOptions();
            }


            renderHeader() {
                const timeField = this.findField(this.rootData, ['time', '时候']);
                const locField = this.findField(this.rootData, ['location', 'place', '地方']);

                if (timeField) {
                    const timeValue = this.rootData[timeField];
                    this.elements.timeDisplay.textContent = this.cleanText(timeValue);
                    this.elements.timeDisplay.parentNode.querySelector('.emoji').textContent = this.getEmoji(timeValue);
                }
                if (locField) {
                    const locValue = this.rootData[locField];
                    this.elements.locationDisplay.textContent = this.cleanText(locValue);
                    this.elements.locationDisplay.parentNode.querySelector('.emoji').textContent = this.getEmoji(locValue);
                }
            }

            renderCharacters() {
                const userListField = this.findField(this.rootData, ['user', 'char', '角色', '人物', '爷们娘们','Những người có mặt']);
                const userList = userListField ? this.rootData[userListField] : [];
                this.elements.charactersContainer.innerHTML = '';
                if (!userList || userList.length === 0) {
                    this.elements.charactersContainer.innerHTML = `<div class="text-center py-4 text-gray-500">Không có ai ở đây</div>`;
                    return;
                }
                userList.forEach(userItem => {
                    const userField = this.findField(userItem, ['user', '角色', '人物', '这人是']);
                    const userData = userField ? userItem[userField] : null;
                    if (userData) this.elements.charactersContainer.appendChild(this.createCharacterCard(userData));
                });
            }

            createCharacterCard(userData) {
                const card = document.createElement('div');
                card.className = 'character-card card-hover rounded-xl border p-4 shadow-sm theme-transition';
                const nameField = this.findField(userData, ['name', '名号']);
                const userName = nameField ? userData[nameField] : 'Không rõ tên';

                let cardContent = `<h3 class="font-bold text-lg mb-3 pb-2 border-b border-gray-700/30 theme-transition">${this.getEmoji(userName)} ${this.cleanText(userName)}</h3>`;

                const processValue = (value) => {
                    return `${this.getEmoji(value)} ${this.cleanText(value)}`;
                };

                let attributesContainer = document.createElement('div');
                card.innerHTML = cardContent;
                card.appendChild(attributesContainer);

                Object.keys(userData).forEach(key => {
                    if (key === nameField) return;

                    const value = userData[key];

                    if (typeof value === 'object' && !Array.isArray(value) && value !== null) {
                        const groupWrapper = document.createElement('div');
                        groupWrapper.className = "mt-2";
                        let groupHTML = `<strong class="text-primary">${this.getEmoji(key)} ${key}:</strong>`;
                        groupHTML += '<div class="grid grid-cols-1 md:grid-cols-2 gap-x-4 gap-y-2.5 mt-1 pl-2">';
                        Object.keys(value).forEach(subKey => {
                            const subValue = value[subKey];
                            groupHTML += `<div><strong class="text-primary/80">${this.getEmoji(subValue)} ${subKey}:</strong> ${this.cleanText(subValue)}</div>`;
                        });
                        groupHTML += '</div>';
                        groupWrapper.innerHTML = groupHTML;
                        attributesContainer.appendChild(groupWrapper);
                    } else {
                        const simpleAttr = document.createElement('div');
                        simpleAttr.className = "mt-2 text-sm";
                        simpleAttr.innerHTML = `<strong class="text-primary">${this.getEmoji(value)} ${key}:</strong> ${processValue(value)}`;
                        attributesContainer.appendChild(simpleAttr);
                    }
                });

                return card;
            }

            renderActionOptions() {
                const actionField = this.findField(this.rootData, ['action', 'option', '咋整']);
                const actionData = actionField ? this.rootData[actionField] : {};
                const ownerField = this.findField(actionData, ['name', '名号','Tên']);
                const ownerName = ownerField ? actionData[ownerField] : '你';
                this.elements.actionOwner.textContent = this.cleanText(ownerName);
                const optionsField = this.findField(actionData, ['option', '选项']);
                const options = optionsField ? actionData[optionsField] : [];
                this.elements.optionsList.innerHTML = '';
                if(options.length === 0) {
                    this.elements.optionsList.innerHTML = `<li class="text-gray-500">Không có gì để làm</li>`;
                    return;
                }
                options.forEach(opt => {
                    const li = document.createElement('li');
                    li.className = 'pl-2 py-1.5 border-l-2 border-primary/30 theme-transition';
                    li.dataset.fulltext = this.cleanText(opt);
                    const match = this.cleanText(opt).match(/(\[.*?\])(.*)/);
                    if(match){
                        li.innerHTML = `<span class="font-bold text-primary mr-2">${match[1]}</span><span>${match[2].trim()}</span>`;
                    } else {
                        li.textContent = this.cleanText(opt);
                    }
                    this.elements.optionsList.appendChild(li);
                });
            }

            renderEmpty() { Object.values(this.elements).forEach(el => el.innerHTML = '...'); }
            handleError(error) { console.error('状态栏渲染出错:', error); this.elements.charactersContainer.innerHTML = `<div class="text-red-400 p-4">Lỗi hiển thị: ${error.message}</div>`; }
        }
    </script>
</body>
